    # Sort: primary = start from 02:00, secondary = end time
    def _start_sort(s):
        s = str(s).strip()
        if not is_time_text(s): return 9999
        return (time_to_minutes(s) - 2 * 60) % (24 * 60)

    def _end_sort(s):
        s = str(s).strip()
        if not is_time_text(s): return 9999
        return (time_to_minutes(s) - 2 * 60) % (24 * 60)

